import React, { useState, useEffect } from 'react';
import { Package, Bike, CheckCircle2 } from 'lucide-react';

const SeguimientoPedido = ({ pedido, onFinalizar }) => {
  const [fase, setFase] = useState(1); 
  const [progreso, setProgreso] = useState(0);

  useEffect(() => {
    const tiempoFase1 = 8000; 
    const tiempoFase2 = 10000; 
    const intervaloMs = 100;

    const timer = setInterval(() => {
      setProgreso((prev) => {
        if (fase === 1) {
          if (prev >= 100) {
            setFase(2);
            return 0;
          }
          return prev + (100 / (tiempoFase1 / intervaloMs));
        } else if (fase === 2) {
          if (prev >= 100) {
            setFase(3);
            clearInterval(timer);
            return 100;
          }
          return prev + (100 / (tiempoFase2 / intervaloMs));
        }
        return 100;
      });
    }, intervaloMs);

    if (fase === 3) {
      const finalTimeout = setTimeout(() => {
        if (onFinalizar) onFinalizar(pedido.id);
      }, 3000);
      return () => clearTimeout(finalTimeout);
    }

    return () => clearInterval(timer);
  }, [fase, pedido.id, onFinalizar]);

  return (
    <div style={card}>
      {/* Cabecera estilo App */}
      <div style={header}>
        <div style={infoEntrega}>
          <span style={textChico}>Llegada estimada: Hoy</span>
          <div style={badgeEnHora}>En hora</div>
          <h2 style={horaEstilo}>{fase === 3 ? "¡Llegó!" : "10:15 - 10:45"}</h2>
        </div>
        <div style={cajaLogo}>
          <div style={logoSimulado}>P</div>
        </div>
      </div>

      {/* BARRA SEGMENTADA (Estilo la imagen enviada) */}
      <div style={contenedorBarra}>
        {[1, 2, 3, 4].map((segmento) => {
          let llenado = 0;
          if (fase === 1) {
            // Dividimos el progreso de la fase 1 en los dos primeros segmentos
            if (segmento === 1) llenado = Math.min(progreso * 2, 100);
            if (segmento === 2) llenado = progreso > 50 ? (progreso - 50) * 2 : 0;
          } else if (fase === 2) {
            // Fase 2 llena los segmentos 3 y 4
            llenado = 100; // Segmentos 1 y 2 ya llenos
            if (segmento === 3) llenado = Math.min(progreso * 2, 100);
            if (segmento === 4) llenado = progreso > 50 ? (progreso - 50) * 2 : 0;
          } else if (fase === 3) {
            llenado = 100;
          }

          return (
            <div key={segmento} style={segmentoGris}>
              <div style={{ ...segmentoColor, width: `${llenado}%` }} />
            </div>
          );
        })}
      </div>

      {/* Estado con Texto Dinámico */}
      <div style={estadoContenedor}>
        <span style={textoEstado}>
          {fase === 1 && "El local está preparando tu pedido"}
          {fase === 2 && "El cadete está llevando tu pedido"}
          {fase === 3 && "¡Pedido entregado con éxito!"}
        </span>
        <span style={flecha}>⌄</span>
      </div>
    </div>
  );
};

// --- ESTILOS INSPIRADOS EN LA IMAGEN ---
const card = {
  background: 'white',
  padding: '20px',
  borderRadius: '12px',
  boxShadow: '0 4px 12px rgba(0,0,0,0.08)',
  maxWidth: '450px',
  fontFamily: 'sans-serif'
};

const header = { display: 'flex', justifyContent: 'space-between', marginBottom: '15px' };
const infoEntrega = { display: 'flex', flexDirection: 'column', gap: '4px' };
const textChico = { fontSize: '13px', color: '#444' };
const badgeEnHora = { background: '#4ef0c6', color: '#000', padding: '2px 8px', borderRadius: '4px', fontSize: '11px', fontWeight: 'bold', width: 'fit-content' };
const horaEstilo = { margin: '5px 0', fontSize: '28px', fontWeight: '800', color: '#1a1a1a' };

const cajaLogo = { background: '#f5a623', width: '50px', height: '50px', borderRadius: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const logoSimulado = { color: 'white', fontWeight: 'bold', fontSize: '24px', fontStyle: 'italic' };

const contenedorBarra = { display: 'flex', gap: '6px', marginBottom: '15px' };
const segmentoGris = { flex: 1, height: '6px', background: '#e0e0e0', borderRadius: '10px', overflow: 'hidden' };
const segmentoColor = { height: '100%', background: '#5bc0de', transition: 'width 0.1s linear' };

const estadoContenedor = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderTop: '1px solid #eee', paddingTop: '12px' };
const textoEstado = { fontSize: '15px', fontWeight: '600', color: '#1a1a1a' };
const flecha = { fontSize: '18px', color: '#888' };

export default SeguimientoPedido;
